import os
from google.cloud import storage, firestore, pubsub_v1
from google.oauth2 import service_account

# Define the service account path
service_account_path = "path/to/your/service-account.json"

# Load the service account credentials
credentials = service_account.Credentials.from_service_account_file(service_account_path)

# Define all the clients
storage_client = storage.Client(credentials=credentials, project='your-project-id')
firestore_client = firestore.Client(credentials=credentials, project='your-project-id')
publisher_client = pubsub_v1.PublisherClient(credentials=credentials)

# Other configurations
bucket_name = 'your-bucket-name'
topic_path = publisher_client.topic_path('your-project-id', 'your-topic-name')

def process_file(event, context):
    # Get file from GCP Storage
    bucket = storage_client.get_bucket(bucket_name)
    blob = bucket.get_blob(event['name'])
    data = blob.download_as_text()

    # Write data to Firestore
    doc_ref = firestore_client.collection('your-collection-name').document()
    doc_ref.set({'data': data})

    # Publish the name of processed file to the Pub/Sub topic
    publisher_client.publish(topic_path, event['name'].encode('utf-8'))